};

defineExpose({ open });
const emit = defineEmits(['sheetDone']);
const inPara = defineProps({});

onMounted(() => {});

//表单开启
function open(openType, data, []) {
    formState.value = openType;
    sheetData.value = data;
    dialogShow.value = true;
}

//表单完成
function formDone(res) {
    executeRes(res, translate, () => {
        emit('sheetDone');
        dialogShow.value = false;
    });
}

//提交
function btnSubmit() {
    formRef.value
        ?.validate((errors) => {
            if (!errors) {
                if (formState.value == 'add') {
                    Add(sheetData.value, itemName).then((res) => {
                        formDone(res);
                    });
                } else {
                    Update(sheetData.value, itemName).then((res) => {
                        formDone(res);
                    });
                }
            }
        })
        .catch((err) => {
            window.$message.warning(err[0][0].message);
        });
}

//取消
function btnCancel() {
    sheetData.value = {};
    dialogShow.value = false;
}
//rfa_path上传返回
function rfa_path_uploadDone(data) {
    // console.log(data);
    sheetData.value.rfa_path = data.file_fullpath;
}
